/**
 * EdgeField
 *
 * The "edge-detection filter" look, now baked ahead of time instead of
 * computed live. The original SVG pipeline (feTurbulence -> posterize ->
 * feConvolveMatrix Laplacian -> luminanceToAlpha) is deterministic and the
 * layer is inert, so there's nothing to gain from re-running it in the
 * browser. It's rendered once by scripts/bake-edge-field.py into
 * public/edge-field-mask.webp — a transparent image whose alpha channel IS
 * the contour pattern. We use it as a CSS mask, which lets --glow-color
 * stay fully dynamic (theme swaps, dark mode, etc.) without touching the
 * baked asset.
 *
 * Regenerate the mask with: python3 scripts/bake-edge-field.py
 */

const MASK_URL =
  'data:image/webp;base64,';

const maskLayerStyle: React.CSSProperties = {
  WebkitMaskImage: `url(${MASK_URL})`,
  maskImage: `url(${MASK_URL})`,
  WebkitMaskSize: 'cover',
  maskSize: 'cover',
  WebkitMaskRepeat: 'no-repeat',
  maskRepeat: 'no-repeat',
  WebkitMaskPosition: 'center',
  maskPosition: 'center'
};

export function EdgeFieldMask() {
  return (
    <div className="pointer-events-none fixed inset-0 h-screen w-screen overflow-hidden">
      {/* Sharp contour lines */}
      <div
        className="absolute inset-0"
        style={{
          ...maskLayerStyle,
          backgroundColor: 'var(--glow-color)',
          opacity: 'var(--glow-strength-rest)'
        }}
        aria-hidden="true"
      />

      {/* Bloom: same mask, blurred and dimmer, standing in for the old feGaussianBlur + feMerge pass */}
      <div
        className="absolute inset-0"
        style={{
          ...maskLayerStyle,
          backgroundColor: 'var(--glow-color)',
          opacity: 'calc(var(--glow-strength-rest) * 0.55)',
          filter: 'blur(3px)'
        }}
        aria-hidden="true"
      />

      {/* Vignette to keep the center readable */}
      <div
        className="absolute inset-0"
        style={{
          background:
            'radial-gradient(135% 110% at 50% 35%, transparent 55%, color-mix(in oklch, var(--background) 82%, transparent) 100%)'
        }}
      />
    </div>
  );
}
